sql:
SELECT year, AVG(average_income_growth) AS average_income_growth
FROM elections
GROUP BY year;

SELECT AVG(incumbent_vote_share) AS average_incumbent_vote_share
FROM elections
WHERE year BETWEEN 1950 AND 1960;

SELECT year, incumbent_win
FROM elections
ORDER BY year ASC;

SELECT AVG(average_income_growth) AS average_income_growth_1952
FROM elections
WHERE year = 1952 AND incumbent_win = 1;

external_knowledge:
- "storm of fallen heroes" is a metaphorical term referring to military fatalities;
- "electoral battles" metaphorically refers to elections;
- "per million souls" implies the per million population rate;
- "incumbent emerged victorious" means the incumbent won the election.

sql:
SELECT AVG(average_income_growth) AS average_income_growth, COUNT(year) AS years_won_more_than_50_percent
FROM elections
WHERE incumbent_vote_share > 50;

SELECT avg_income_growth, unemployment_rate
FROM economic_indicators
WHERE year = 1956;

SELECT AVG(avg_income_growth) AS average_income_growth_over_last_five_years
FROM economic_indicators
WHERE year BETWEEN (SELECT MAX(year) - 4 FROM economic_indicators) AND (SELECT MAX(year) FROM economic_indicators);

SELECT election_id
FROM elections
WHERE year = 1952;

SELECT T1.avg_income_growth
FROM economic_indicators AS T1
INNER JOIN elections AS T2 ON T1.year = T2.year;
